const input = $input.first().json;
const topic = input['Image Topic / Idea'];
const platform = input['Platform'];
const style = input['Style'];

const aspectMap = {
  'Instagram Post (1:1)': '1:1',
  'Instagram Story (9:16)': '9:16',
  'LinkedIn Post (3:2)': '3:2',
  'Twitter/X Post (16:9)': '16:9',
  'Facebook Post (3:2)': '3:2'
};

const styleMap = {
  'Professional & Corporate': 'professional photography, corporate clean aesthetic, soft studio lighting, high-end commercial look, sharp focus, minimal background clutter',
  'Vibrant & Viral': 'vibrant saturated colors, eye-catching composition, dynamic lighting, trending social media aesthetic, high engagement visual style',
  'Minimal & Clean': 'minimalist composition, clean negative space, soft muted tones, elegant simplicity, modern flat design feel',
  'Bold & Colorful': 'bold color contrast, punchy graphic style, high energy composition, striking visual impact'
};

const qualityBoost = 'ultra high detail, 8k resolution, sharp focus, professional photography, perfect composition, social media ready, no text overlay, no watermark, no logo';

const finalPrompt = `${topic}, ${styleMap[style] || styleMap['Professional & Corporate']}, ${qualityBoost}`;

return [{
  json: {
    prompt: finalPrompt,
    aspect_ratio: aspectMap[platform] || '1:1',
    platform,
    style,
    topic
  }
}];
